"use client"

import { useState, useEffect, useMemo, use } from "react";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Settings, Share2, MapPin, Loader2, UserCircle, Car, Gauge, Cpu, Zap, ChevronLeft, Trash2, Palette, LogOut, X } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { 
  AlertDialog, 
  AlertDialogAction, 
  AlertDialogCancel, 
  AlertDialogContent, 
  AlertDialogDescription, 
  AlertDialogFooter, 
  AlertDialogHeader, 
  AlertDialogTitle, 
  AlertDialogTrigger 
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { useUser, useDoc, useFirestore, useMemoFirebase, updateDocumentNonBlocking, useCollection, deleteDocumentNonBlocking, useAuth } from "@/firebase";
import { doc, collection, query, orderBy, getDocs, where } from "firebase/firestore";
import { signOut } from "firebase/auth";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";
import { RenderCarIcon, CarIconType } from "@/components/icons/car-icons";

export default function ProfileViewPage({ 
  params
}: { 
  params: Promise<{ userId: string }>
}) {
  const { userId: targetUserId } = use(params);
  const router = useRouter();
  const { user: currentUser } = useUser();
  const auth = useAuth();
  const isOwnProfile = currentUser?.uid === targetUserId;
  const db = useFirestore();
  const { toast } = useToast();
  
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [formData, setFormData] = useState({
    username: "",
    city: "",
    carBrand: "",
    carModel: "",
    carColor: "",
    horsepower: 0,
    modifications: "",
    profileIcon: "speedometer" as CarIconType,
  });

  const profileRef = useMemoFirebase(() => {
    if (!targetUserId || !db) return null;
    return doc(db, "users", targetUserId);
  }, [targetUserId, db]);

  const { data: profile, isLoading: isProfileLoading } = useDoc(profileRef);

  const runsQuery = useMemoFirebase(() => {
    if (!targetUserId || !db) return null;
    return query(
      collection(db, "users", targetUserId, "runs"),
      orderBy("createdAt", "desc")
    );
  }, [targetUserId, db]);

  const { data: runs } = useCollection(runsQuery);

  const stats = useMemo(() => {
    if (!runs) return { totalRuns: 0, totalKm: "0.00", peak: 0, best0to60: "--", best0to100: "--", best100to200: "--" };
    
    const totalDistance = runs.reduce((acc, run) => acc + (run.distanceMeters || 0), 0);
    const peakSpeed = runs.reduce((max, run) => Math.max(max, run.peakSpeedKmH || 0), 0);
    
    const zeroTo60Runs = runs.filter(r => r.runType === "0-60" && r.dragTime);
    const best0to60 = zeroTo60Runs.length > 0 
      ? Math.min(...zeroTo60Runs.map(r => r.dragTime)).toFixed(2) + "s" 
      : "--";

    const zeroTo100Runs = runs.filter(r => r.runType === "0-100" && r.dragTime);
    const best0to100 = zeroTo100Runs.length > 0 
      ? Math.min(...zeroTo100Runs.map(r => r.dragTime)).toFixed(2) + "s" 
      : "--";

    const hundredTo200Runs = runs.filter(r => r.runType === "100-200" && r.dragTime);
    const best100to200 = hundredTo200Runs.length > 0 
      ? Math.min(...hundredTo200Runs.map(r => r.dragTime)).toFixed(2) + "s" 
      : "--";

    return {
      totalRuns: runs.length,
      totalKm: (totalDistance / 1000).toFixed(2),
      peak: peakSpeed,
      best0to60,
      best0to100,
      best100to200
    };
  }, [runs]);

  useEffect(() => {
    if (profile && isOwnProfile) {
      setFormData({
        username: profile.username || "",
        city: profile.city || "",
        carBrand: profile.carBrand || "",
        carModel: profile.carModel || "",
        carColor: profile.carColor || "",
        horsepower: profile.horsepower || 0,
        modifications: profile.modifications || "",
        profileIcon: (profile.profileIcon as CarIconType) || "speedometer",
      });
    }
  }, [profile, isOwnProfile]);

  const handleSaveProfile = () => {
    if (!profileRef || !isOwnProfile) return;

    const updatedData = {
      ...formData,
      horsepower: Number(formData.horsepower),
      updatedAt: new Date().toISOString(),
    };

    updateDocumentNonBlocking(profileRef, updatedData);
    toast({ title: "PROFILI U PËRDITËSUA", description: "Të dhënat u ruajtën me sukses." });
    setIsEditDialogOpen(false);
  };

  const handleSignOut = async () => {
    try {
      await signOut(auth);
      router.replace("/");
      toast({ title: "DOLE ME SUKSES", description: "Shihemi së shpejti!" });
    } catch (e) {
      toast({ variant: "destructive", title: "Gabim", description: "Dështoi dalja nga llogaria." });
    }
  };

  const handleResetStats = async () => {
    if (!db || !targetUserId || !isOwnProfile) return;
    setIsResetting(true);
    
    try {
      const userRunsRef = collection(db, "users", targetUserId, "runs");
      const userRunsSnap = await getDocs(userRunsRef);
      userRunsSnap.forEach((d) => {
        deleteDocumentNonBlocking(doc(db, "users", targetUserId, "runs", d.id));
      });

      const publicRunsRef = collection(db, "public_runs");
      const q = query(publicRunsRef, where("userId", "==", targetUserId));
      const publicRunsSnap = await getDocs(q);
      publicRunsSnap.forEach((d) => {
        deleteDocumentNonBlocking(doc(db, "public_runs", d.id));
      });

      toast({
        title: "STATISTIKAT U RESETUAN",
        description: "Të gjitha të dhënat dhe rekordet janë fshirë.",
      });
      setIsEditDialogOpen(false);
    } catch (error) {
      console.error("Error resetting stats:", error);
      toast({ variant: "destructive", title: "Gabim", description: "Dështoi resetimi." });
    } finally {
      setIsResetting(false);
    }
  };

  if (isProfileLoading) {
    return (
      <div className="flex flex-col min-h-screen bg-background items-center justify-center">
        <Loader2 className="w-10 h-10 text-accent animate-spin" />
      </div>
    );
  }

  if (!profile) {
    return (
      <div className="flex flex-col min-h-screen bg-background items-center justify-center p-10 text-center safe-top apple-scale-in">
        <UserCircle className="w-16 h-16 text-muted-foreground mb-6 opacity-20" />
        <h1 className="text-2xl font-black uppercase">NUK U GJET</h1>
        <Button onClick={() => router.back()} variant="ghost" className="mt-6 text-accent uppercase font-black transition-transform active:scale-90">KTHEHU MBRAPA</Button>
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 safe-top overflow-x-hidden no-scrollbar">
      <div className="p-6 flex justify-between items-center z-20 shrink-0 apple-slide-up">
        <div className="flex items-center gap-2">
           <Button onClick={() => router.back()} size="icon" variant="ghost" className="rounded-2xl hover:bg-white/5 h-12 w-12 transition-transform active:scale-90"><ChevronLeft className="w-7 h-7" /></Button>
           <h1 className="text-2xl font-black uppercase tracking-tighter">PROFILI</h1>
        </div>
        <div className="flex gap-3">
          {isOwnProfile && (
            <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
              <DialogTrigger asChild>
                <Button size="icon" variant="outline" className="rounded-2xl glass border-white/10 w-12 h-12 transition-all hover:border-accent/40 active:scale-90">
                  <Settings className="w-5 h-5" />
                </Button>
              </DialogTrigger>
              <DialogContent className="glass border-white/10 text-foreground w-[92%] sm:max-w-[425px] max-h-[85vh] overflow-y-auto no-scrollbar rounded-[2.5rem] p-8 apple-scale-in">
                <DialogHeader className="flex flex-row items-center justify-between">
                  <DialogTitle className="text-2xl font-black uppercase tracking-tighter">PËRDITËSO PROFILIN</DialogTitle>
                  <button 
                    onClick={() => setIsEditDialogOpen(false)}
                    className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center hover:bg-white/10 transition-colors"
                  >
                    <X className="w-5 h-5 text-white/40" />
                  </button>
                </DialogHeader>
                <div className="grid gap-6 py-6">
                  <div className="grid gap-2">
                    <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">EMRI I PËRDORUESIT</Label>
                    <Input value={formData.username} onChange={(e) => setFormData({...formData, username: e.target.value})} className="bg-white/5 border-white/10 rounded-2xl h-14 font-black uppercase text-sm" />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="grid gap-2">
                      <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">MARKA</Label>
                      <Input value={formData.carBrand} onChange={(e) => setFormData({...formData, carBrand: e.target.value})} className="bg-white/5 border-white/10 rounded-2xl h-14 font-black uppercase text-sm" />
                    </div>
                    <div className="grid gap-2">
                      <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">MODELI</Label>
                      <Input value={formData.carModel} onChange={(e) => setFormData({...formData, carModel: e.target.value})} className="bg-white/5 border-white/10 rounded-2xl h-14 font-black uppercase text-sm" />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="grid gap-2">
                      <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">HORSEPOWER</Label>
                      <Input type="number" value={formData.horsepower} onChange={(e) => setFormData({...formData, horsepower: parseInt(e.target.value) || 0})} className="bg-white/5 border-white/10 rounded-2xl h-14 font-black text-sm" />
                    </div>
                    <div className="grid gap-2">
                      <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">NGJYRA</Label>
                      <Input value={formData.carColor} onChange={(e) => setFormData({...formData, carColor: e.target.value})} className="bg-white/5 border-white/10 rounded-2xl h-14 font-black uppercase text-sm" />
                    </div>
                  </div>
                  <div className="grid gap-2">
                    <Label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground ml-1">MODIFIKIMET</Label>
                    <Textarea value={formData.modifications} onChange={(e) => setFormData({...formData, modifications: e.target.value})} className="bg-white/5 border-white/10 rounded-2xl min-h-[100px] font-light" />
                  </div>

                  <div className="mt-4 pt-6 border-t border-white/5 space-y-4">
                    <AlertDialog>
                      <AlertDialogTrigger asChild>
                        <Button variant="outline" className="w-full h-14 border-red-500/20 bg-red-500/5 text-red-500 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all hover:bg-red-500/10 active:scale-95">
                          <Trash2 className="w-4 h-4 mr-2" /> RESETO STATISTIKAT
                        </Button>
                      </AlertDialogTrigger>
                      <AlertDialogContent className="glass border-white/10 rounded-[3rem] w-[92%] p-10 apple-scale-in">
                        <AlertDialogHeader>
                          <AlertDialogTitle className="text-xl font-black uppercase tracking-tighter text-white">KONFIRMIM</AlertDialogTitle>
                          <AlertDialogDescription className="text-sm font-light text-muted-foreground mt-2">
                            Ky veprim do të fshijë përgjithmonë të gjitha rekordet tuaja të garave.
                          </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter className="mt-8 flex-row gap-4">
                          <AlertDialogCancel className="flex-1 rounded-2xl border-white/10 text-[11px] h-14 font-black uppercase">ANULO</AlertDialogCancel>
                          <AlertDialogAction 
                            onClick={handleResetStats} 
                            disabled={isResetting}
                            className="flex-1 bg-red-600 text-white rounded-2xl text-[11px] h-14 font-black uppercase transition-all active:scale-95"
                          >
                            KONFIRMO
                          </AlertDialogAction>
                        </AlertDialogFooter>
                      </AlertDialogContent>
                    </AlertDialog>

                    <Button variant="outline" onClick={handleSignOut} className="w-full h-14 border-white/10 bg-white/5 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all hover:bg-white/10 active:scale-95">
                      <LogOut className="w-4 h-4 mr-2 text-accent" /> DALJA NGA LLOGARIA
                    </Button>
                  </div>
                </div>
                <DialogFooter className="pt-4"><Button onClick={handleSaveProfile} className="w-full bg-accent text-background font-black uppercase rounded-[1.8rem] h-16 shadow-2xl transition-all active:scale-95">RUAJ NDRYSHIMET</Button></DialogFooter>
              </DialogContent>
            </Dialog>
          )}
          <Button size="icon" variant="outline" className="rounded-2xl glass border-white/10 w-12 h-12 transition-all active:scale-90"><Share2 className="w-5 h-5" /></Button>
        </div>
      </div>

      <div className="px-8 py-4 relative z-10 flex flex-col items-center text-center apple-slide-up stagger-1">
        <div className="relative w-36 h-36 mb-6">
          <div className="absolute inset-0 rounded-[2.5rem] bg-accent/20 blur-3xl opacity-50 animate-pulse-glow" />
          <div className="relative w-full h-full rounded-[2.5rem] bg-zinc-950 border-4 border-white/5 shadow-2xl flex items-center justify-center overflow-hidden apple-scale-in">
            <RenderCarIcon type={profile?.profileIcon} className="w-20 h-20 text-accent drop-shadow-[0_0_15px_rgba(77,224,244,0.6)]" />
          </div>
        </div>

        <div className="space-y-3 apple-slide-up stagger-2">
          <h1 className="text-3xl font-black tracking-tighter uppercase leading-none">{profile?.username}</h1>
          <div className="flex flex-col items-center gap-2">
            <Badge variant="outline" className="bg-accent/10 border-accent/20 text-accent font-black px-5 py-1 rounded-full text-[10px] tracking-widest apple-scale-in">
              {profile?.isPremium ? 'PREMIUM MEMBER' : 'SHOFER KOSOVAR'}
            </Badge>
            <div className="flex items-center gap-2 text-[10px] font-black text-muted-foreground uppercase bg-white/5 px-5 py-1.5 rounded-full border border-white/5 tracking-widest apple-scale-in stagger-3">
              <MapPin className="w-3.5 h-3.5 text-accent" />
              {profile?.city}
            </div>
          </div>
        </div>

        <div className="flex gap-3 w-full mt-8 apple-slide-up stagger-4">
          {[
            { label: "KM TOTAL", val: stats.totalKm },
            { label: "GARA", val: stats.totalRuns.toString() },
            { label: "PEAK SPEED", val: `${stats.peak}`, accent: true }
          ].map((stat, i) => (
            <div key={i} className="flex-1 glass rounded-3xl p-5 border-white/5 flex flex-col items-center transition-all duration-300 hover:scale-105">
              <p className="text-[9px] font-light text-muted-foreground uppercase tracking-widest mb-1.5">{stat.label}</p>
              <p className={cn("text-xl font-black text-white", stat.accent && "text-accent")}>{stat.val}</p>
            </div>
          ))}
        </div>
      </div>

      <div className="px-8 mt-8 space-y-6 apple-slide-up stagger-5">
        <h2 className="text-[11px] font-black uppercase tracking-[0.3em] text-muted-foreground px-1">SPECIFIKAT E MJETIT</h2>
        <Card className="glass border-accent/20 p-8 rounded-[2.5rem] space-y-8 shadow-2xl transition-all hover:border-accent/40">
          <div className="flex flex-col gap-2">
            <div className="flex items-center gap-4">
              <div className="w-1.5 h-10 bg-accent rounded-full apple-scale-in" />
              <div>
                <h3 className="text-3xl font-black text-white uppercase tracking-tighter leading-none mb-1">{profile?.carBrand}</h3>
                <p className="text-lg font-black text-accent/80 uppercase tracking-tighter leading-none">{profile?.carModel}</p>
              </div>
            </div>
            <div className="mt-4 flex flex-wrap gap-3">
              <Badge className="bg-white/5 border-white/10 text-accent font-black text-[10px] px-4 py-1.5 rounded-xl tracking-widest apple-scale-in"><Cpu className="w-4 h-4 mr-2" />{profile?.horsepower} HP</Badge>
              <Badge className="bg-white/5 border-white/10 text-accent font-black text-[10px] px-4 py-1.5 rounded-xl tracking-widest apple-scale-in"><Palette className="w-4 h-4 mr-2" />{profile?.carColor}</Badge>
            </div>
          </div>
          <div className="grid grid-cols-4 gap-2 pt-8 border-t border-white/10">
            {[ 
              { label: "0-60", val: stats.best0to60, icon: Zap },
              { label: "0-100", val: stats.best0to100, icon: Zap }, 
              { label: "100-200", val: stats.best100to200, icon: Gauge }, 
              { label: "TOP SPEED", val: `${stats.peak}`, icon: Car } 
            ].map((stat, i) => (
              <div key={i} className="text-center apple-scale-in">
                <p className="text-[7px] font-light text-muted-foreground uppercase tracking-widest mb-3 flex items-center justify-center gap-1.5">
                  <stat.icon className="w-3 h-3" />{stat.label}
                </p>
                <div className="flex flex-col items-center">
                  <span className="text-base font-black text-white leading-none tracking-tighter italic">{stat.val}</span>
                </div>
              </div>
            ))}
          </div>
        </Card>

        <div className="glass rounded-3xl p-6 border-white/5 space-y-4 apple-slide-up stagger-5">
          <h4 className="text-[10px] font-black text-accent uppercase tracking-[0.2em] flex items-center gap-2"><Zap className="w-4 h-4" />MODIFIKIMET</h4>
          <div className="flex flex-wrap gap-2">
            {profile?.modifications ? profile.modifications.split(',').map((mod: string, i: number) => (
              <Badge key={i} variant="outline" className="bg-white/5 border-white/10 text-[10px] font-black px-4 py-2 rounded-xl uppercase tracking-wider apple-scale-in">{mod.trim()}</Badge>
            )) : <p className="text-[11px] font-light text-muted-foreground uppercase tracking-widest px-1">NUK KA MODIFIKIME TË SHËNUARA</p>}
          </div>
        </div>
      </div>
      <BottomNav />
    </div>
  );
}